const body = $input.first().json.body || {};

// Support both direct webhook calls and relay from events receiver
const text      = body.text || body.message || '';
const channelId = body.channel_id || body.channel || 'C0AJW9DTDSB';
const userId    = body.user_id || body.user || 'unknown';
const threadTs  = body.thread_ts || body.ts || '';
const userName  = body.user_name || body.username || 'unknown';

// Strip bot @mentions
const cleanText = text.replace(/<@[^>]+>/g, '').trim();

return [{ json: { text: cleanText, rawText: text, channelId, userId, userName, threadTs } }];

const raw = $input.first().json.message?.content || '';
const parsed = $('Parse Input').first().json;

let classification;
try {
  // Extract JSON from the response (handle markdown code blocks)
  const jsonMatch = raw.match(/```(?:json)?\s*([\s\S]*?)\s*```/) ||
                    raw.match(/(\{[\s\S]*\})/);
  const jsonStr = jsonMatch ? jsonMatch[1] : raw;
  classification = JSON.parse(jsonStr.trim());
} catch(e) {
  // Fallback: if parsing fails, mark as ignore
  classification = { type: 'ignore', reasoning: 'Could not parse Ollama response' };
}

// Map priority strings to Linear priority integers
const PRIORITY_MAP = { urgent: 1, high: 2, medium: 3, low: 4 };
const priorityInt = PRIORITY_MAP[classification.priority] || 3;

return [{ json: {
  ...parsed,
  classification,
  issueType:   classification.type,
  title:       classification.title || parsed.text.slice(0, 80),
  description: classification.description || parsed.text,
  priority:    priorityInt,
  labels:      classification.labels || [],
  estimate:    classification.estimate || null,
  reasoning:   classification.reasoning || '',
  shouldCreate: classification.type !== 'ignore'
}}];

