={{ (() => {
  const teams = $('Get Linear Teams').first().json.data?.teams?.nodes || [];
  const teamId = teams[0]?.id || '';   // Use first team; adjust if needed
  const d = $('Parse Classification').first().json;

  // Build label IDs string (Linear requires label IDs not names — we'll use title-based approach)
  const desc = d.description + '\n\n---\n*Source:* Slack message from <@' + d.userId + '> in <#' + d.channelId + '>\n*AI reasoning:* ' + d.reasoning;

  const mutation = `
    mutation CreateIssue($input: IssueCreateInput!) {
      issueCreate(input: $input) {
        success
        issue {
          id
          identifier
          title
          url
          priority
          state { name }
        }
      }
    }
  `;

  const variables = {
    input: {
      teamId:      teamId,
      title:       d.title,
      description: desc,
      priority:    d.priority,
      estimate:    d.estimate
    }
  };

  return JSON.stringify({ query: mutation, variables });
})() }}

