const issue = $input.first().json.data?.issueCreate?.issue;
const d     = $('Parse Classification').first().json;

if (!issue) {
  return [{ json: {
    channelId: d.channelId,
    threadTs:  d.threadTs,
    payload: JSON.stringify({
      channel: d.channelId,
      thread_ts: d.threadTs,
      text: '⚠️ Linear issue creation failed. Check LINEAR_API_KEY env var.'
    })
  }}];
}

const TYPE_EMOJI = { epic:'🗺️', story:'📖', task:'✅', bug:'🐛', idea:'💡' };
const PRIORITY_LABEL = { 1:'🔴 Urgent', 2:'🟠 High', 3:'🟡 Medium', 4:'🔵 Low' };

const emoji    = TYPE_EMOJI[d.issueType] || '✅';
const priority = PRIORITY_LABEL[d.priority] || 'Medium';
const labelsStr = d.labels.length ? d.labels.map(l=>'`'+l+'`').join(' ') : '';

const blocks = [
  {
    type: 'section',
    text: { type: 'mrkdwn', text:
      `${emoji} *<${issue.url}|${issue.identifier}: ${issue.title}>* created in Linear\n` +
      `*Type:* ${d.issueType}  |  *Priority:* ${priority}${labelsStr ? '  |  *Labels:* '+labelsStr : ''}`
    }
  },
  {
    type: 'context',
    elements: [{ type: 'mrkdwn', text: `_${d.reasoning}_` }]
  }
];

return [{ json: {
  channelId: d.channelId,
  threadTs:  d.threadTs,
  payload: JSON.stringify({
    channel:   d.channelId,
    thread_ts: d.threadTs || undefined,
    blocks
  })
}}];
